//-------------------------------------------------------------------------
// 장비 등록, 수정 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
  // 취소 확인
  scwin.f_ContentsDisable();
  if (ds_fixEquipment.getRowPosition() > ds_fixEquipment.getRowCount() || ds_fixEquipment.getModifiedIndex().length > 0) {
    //ds_fixEquipment.undo(ds_fixEquipment.getRowPosition());
    $c.data.undoRow($p, ds_fixEquipment, "Y");
  }
  $c.gus.cfDisableBtn($p, [b_Cancel, b_Cancel2, b_Save, b_Save2]);
  scwin.txt_saveType = "4"; // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  let vRowStatus = ds_fixEquipment.getRowStatus(ds_fixEquipment.getRowPosition());
  let ret;

  // 필수항목 체크
  ret = await $c.gus.cfValidate($p, [chkRegistInfo]);
  if (!ret) {
    return false;
  }

  // 필수항목 체크
  ret = await $c.gus.cfValidate($p, [regData, eqChgDt]);
  if (!ret) {
    return false;
  }

  // ************************************
  // **** 최초등록일자에 대해서만 더블 체크 *****
  // ************************************
  ret = await $c.gus.cfValidate($p, [firstRegDt]);
  if (!ret) {
    return false;
  }
  scwin.txt_saveType = "3"; // 타입이 저장

  //변경한 데이터가 있는지 체크한다. 
  if (ds_fixEquipment.getModifiedIndex().length === 0) {
    $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  if (vRowStatus === 'C') {
    // AsIs 1 create 
    let vCurrentRowVehclShortCd = ds_fixEquipment.getCellData(ds_fixEquipment.getRowPosition(), "vehclShortCd");
    lux_sysCls.setSelectedIndex(0);
    lux_qryCond.setSelectedIndex(2);
    qryCntn.setValue(vCurrentRowVehclShortCd);
  }

  // 저장확인 
  ret = await $c.win.confirm($p, "저장하시겠습니까?");
  if (ret === true) {
    scwin.pos_groupCode = ds_fixEquipment.getRowPosition();
    let depositAdptClsCd = ds_fixEquipment.getCellData(scwin.pos_groupCode, "depositAdptClsCd");
    if (depositAdptClsCd && depositAdptClsCd.length === 6) {
      depositAdptClsCd = depositAdptClsCd.substring(0, 4) + "-" + depositAdptClsCd.substring(4, 6);
      ds_fixEquipment.setCellData(scwin.pos_groupCode, "depositAdptClsCd", depositAdptClsCd);
    }

    //tr_saveFixEquipment.Action ="/cm.bc.eq.eqmgnt.cmd.SaveFixEquipmentInformationCMD.do";
    //tr_saveFixEquipment.Post();
    $c.sbm.execute($p, sbm_saveFixEquipment);
  }
};

