// 장비목록 다운로드
scwin.f_downExcelSheet = async function (e) {
  if (ds_fixEquipment.getRowCount() == 0) {
    await $c.win.alert($p, "조회결과가 존재하지 않습니다.");
    return;
  }
  let fileName = '장비목록';
  let sheetTitle = '장비목록';
  if (await $c.win.confirm($p, "Excel로 다운로드 받으시겠습니까?")) {
    await $c.data.downloadGridViewExcel($p, gr_fixEquipment, {
      fileName: fileName + ".xlsx",
      sheetName: sheetTitle
    });
  }
};

//장비목록 더블클릭
//<!-- Grid Double클릭시  --> 
//<script language=JavaScript for=gr_fixEquipment event=OnDblClick(row,colid)>
scwin.gr_fixEquipment_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
  var row = rowIndex;
  var vEqCd = ds_fixEquipment.getCellData(row, "eqCd");
  var vEqClsCd = ds_fixEquipment.getCellData(row, "eqClsCd");
  var vRowStatus = ds_fixEquipment.getRowStatus(row);
  var vIndex = 0;
  var vTabName = "다른";

  //if(vRowStatus!="1" && vEqClsCd=="LV"){ // 물류차량
  if (vRowStatus != "C" && vEqClsCd == "LV") {
    // 물류차량
    // AsIs 0 normal 1 insert 2 delete  3 update 
    vIndex = 1;
    vTabName = "물류(자차/위수탁)";

    //parent.f_ViewTab(vIndex, vEqCd);
    $c.win.getParent($p).scwin.vEqCd = vEqCd;
    $c.win.getParent($p).tabControl1.setSelectedTabIndex(1);
    $c.win.getParent($p).tabControl1.getWindow().acb_qryCond.setValue("1");
    $c.win.getParent($p).tabControl1.getWindow().ed_qryCntn.setValue(vEqCd);
    $c.win.getParent($p).tabControl1.getWindow().scwin.f_Retrieve();
  } else if (vRowStatus != "C" && vEqClsCd == "LH") {
    // 물류중기
    vIndex = 2;
    vTabName = "물류중기";
    //parent.f_ViewTab(vIndex, vEqCd);
    $c.win.getParent($p).scwin.vEqCd = vEqCd;
    $c.win.getParent($p).tabControl1.setSelectedTabIndex(2);
    $c.win.getParent($p).tabControl1.getWindow().acb_qryCond.setValue("1");
    $c.win.getParent($p).tabControl1.getWindow().ed_qryCntn.setValue(vEqCd);
    $c.win.getParent($p).tabControl1.getWindow().scwin.f_Retrieve();
  } else if (vRowStatus == "C") {
    await $c.win.alert($p, "차량정보 등록을 완료하신후 " + vTabName + " 화면으로 이동이 가능합니다.");
    return false;
  }
};
scwin.ds_fixEquipment_onrowpositionchange = async function (info) {
  var vRowStatus = ds_fixEquipment.getRowStatus(ds_fixEquipment.getRowPosition());
  if (vRowStatus == "R") {
    scwin.txt_saveType = "2";
  } else if (vRowStatus == "C") {
    scwin.txt_saveType = "0";
  } else if (vRowStatus == "U") {
    scwin.txt_saveType = "1";
  }
  if (vRowStatus == 'R') {
    scwin.f_ContentsDisable();
    $c.gus.cfDisableBtn($p, [b_Cancel, b_Cancel2, b_Save, b_Save2]);
  } else if (vRowStatus == 'C') {
    scwin.f_ContentsEnable();
    $c.gus.cfDisableBtn($p, [b_Create, b_Create2, b_Update, b_Update2]);
  } else if (vRowStatus == 'U') {
    scwin.f_ContentsEnable();
    $c.gus.cfDisableBtn($p, [b_Create, b_Create2, b_Update, b_Update2]);
  }
  var vCountRow = ds_fixEquipment.getRowCount();
  var vChgCount = 0;
  var vChgRow = 0;
  for (var i = 0; i < vCountRow; i++) {
    var vCurRowStatus = ds_fixEquipment.getRowStatus(i);
    if (vCurRowStatus == 'C' || vCurRowStatus == 'U') {
      vChgCount++;
      vChgRow = i;
    }
  }
  if (vChgCount > 0 && info.newRowIndex != vChgRow) {
    await $c.win.alert($p, "장비 신규등록이나 변경사항을 저장하신 후에 다른 장비정보로 이동하실수 있습니다.");
    //ds_fixEquipment= vChgRow;
    ds_fixEquipment.setRowPosition(vChgRow);
    gr_fixEquipment.setFocusedCell(vChgRow, 0, false);
    return false;
  }
};
